:root {
  --bg-dark: #0f172a;
  --glass-bg: rgba(30, 41, 59, 0.7);
  --border: rgba(255, 255, 255, 0.1);
  --accent: #38bdf8;
  --text-main: #f1f5f9;
  --text-dim: #94a3b8;
  --success: #10b981;
  --danger: #ef4444;
}

body {
  margin: 0;
  padding: 10px;
  background: transparent;
  font-family: "Inter", -apple-system, sans-serif;
  color: var(--text-main);
}

.glass-container {
  background: var(--glass-bg);
  backdrop-filter: blur(16px);
  border: 1px solid var(--border);
  border-radius: 16px;
  display: flex;
  flex-direction: column;
  height: calc(100vh - 25px);
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5);
}

.table-header {
  padding: 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid var(--border);
}

.header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

h2 {
  margin: 0;
  font-size: 1.2rem;
  font-weight: 600;
  letter-spacing: -0.02em;
  color: var(--accent);
}

.count-badge {
  background: rgba(56, 189, 248, 0.1);
  color: var(--accent);
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 0.75rem;
  font-weight: 600;
  border: 1px solid rgba(56, 189, 248, 0.2);
}

.table-wrapper {
  flex: 1;
  overflow-y: auto;
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  min-width: 600px;
}

th {
  position: sticky;
  top: 0;
  background: #1e293b;
  padding: 14px 20px;
  text-align: left;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
  font-weight: 700;
  z-index: 10;
  border-bottom: 2px solid var(--border);
}

td {
  padding: 14px 20px;
  font-size: 0.875rem;
  border-bottom: 1px solid var(--border);
  transition: all 0.2s;
}

tr:hover {
  background: rgba(255, 255, 255, 0.03);
  cursor: pointer;
}

tr.selected {
  background: rgba(56, 189, 248, 0.15) !important;
  box-shadow: inset 4px 0 0 var(--accent);
}

/* Badges */
.badge {
  padding: 4px 10px;
  border-radius: 6px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
}

.badge-available {
  background: rgba(16, 185, 129, 0.15);
  color: var(--success);
  border: 1px solid rgba(16, 185, 129, 0.3);
  box-shadow: 0 0 15px rgba(16, 185, 129, 0.1);
}

.badge-exhausted {
  background: rgba(239, 68, 68, 0.15);
  color: var(--danger);
  border: 1px solid rgba(239, 68, 68, 0.3);
}

/* Pagination */
.pagination-footer {
  padding: 16px 20px;
  background: rgba(15, 23, 42, 0.5);
  border-top: 1px solid var(--border);
  display: flex;
  justify-content: center;
}

.nav-group {
  display: flex;
  align-items: center;
  gap: 20px;
}

.nav-btn {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--border);
  color: var(--text-main);
  padding: 8px 16px;
  border-radius: 8px;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 600;
  font-size: 0.8rem;
  transition: 0.2s;
}

.nav-btn:hover:not(:disabled) {
  background: var(--accent);
  color: #000;
  border-color: var(--accent);
}

.nav-btn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

#page-info {
  font-size: 0.85rem;
  color: var(--text-dim);
  font-weight: 500;
}

