let currentPage = 1;
const pageSize = 50;
let selectedIndex = -1;
function formatDate(dateStr) {
  if (!dateStr) return "-";
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function formatCurrency(val) {
  const num = parseFloat(val);
  if (isNaN(num)) return val;
  return new Intl.NumberFormat('en-IN', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }).format(num);
}
function render() {
  const data = appsmith.model.tableData || [];
  const columns = appsmith.model.columns || [];
  const totalRecords = data.length;
  const totalPages = Math.ceil(totalRecords / pageSize) || 1;

  // Bounds check
  if (currentPage > totalPages) currentPage = totalPages;
  const start = (currentPage - 1) * pageSize;
  const pageData = data.slice(start, start + pageSize);

  // Render Title & Count
  document.getElementById("table-title").innerText = appsmith.model.title || "Data Grid";
  document.getElementById("data-count").innerText = `${totalRecords} Records`;

  // Render Headers
  const headerRow = document.getElementById("header-row");
  headerRow.innerHTML = columns.map(col => `<th>${col.label}</th>`).join("");

  // Render Body
  const tableBody = document.getElementById("table-body");
  tableBody.innerHTML = pageData.map((item, idx) => {
    const absoluteIdx = start + idx;
    const isSelected = absoluteIdx === selectedIndex;
    return `
            <tr class="${isSelected ? 'selected' : ''}" onclick="selectRow(${absoluteIdx})">
                ${columns.map(col => {
      let val = item[col.key];
      let cellStyle = "";

      // Logic for Currency
      if (col.key.toLowerCase().includes('amount') || col.key === 'mrp') {
        val = formatCurrency(val);
        cellStyle = 'style="text-align: right; font-family: monospace; font-weight: 600;"';
      }

      // Logic for Dates
      if (col.key.toLowerCase().includes('date') || col.key === 'created_at') {
        val = formatDate(val);
      }

      // Logic for Status Badges
      if (col.key === 'status') {
        const state = (val || "").toLowerCase();
        const cls = state === 'available' ? 'badge-available' : 'badge-exhausted';
        val = `<span class="badge ${cls}">${val}</span>`;
      }
      return `<td ${cellStyle}>${val}</td>`;
    }).join("")}
            </tr>
        `;
  }).join("");

  // Pagination Update
  document.getElementById("page-info").innerText = `Page ${currentPage} of ${totalPages}`;
  document.getElementById("prev-btn").disabled = currentPage === 1;
  document.getElementById("next-btn").disabled = currentPage === totalPages;
}
window.selectRow = idx => {
  selectedIndex = idx;
  const selectedRow = appsmith.model.tableData[idx];
  appsmith.updateModel({
    selectedRow: selectedRow
  });
  appsmith.triggerEvent("onRowClick");
  render();
};
document.getElementById("prev-btn").onclick = () => {
  if (currentPage > 1) {
    currentPage--;
    render();
  }
};
document.getElementById("next-btn").onclick = () => {
  const totalPages = Math.ceil(appsmith.model.tableData.length / pageSize);
  if (currentPage < totalPages) {
    currentPage++;
    render();
  }
};
appsmith.onModelChange(() => {
  render();
});

